#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool is_valid(vector<vector<int>>& board, int row, int col, int num) {
        for (int i = 0; i < 9; i++) {
            if (board[row][i] == num) {
                return false;
            }
        }
        for (int i = 0; i < 9; i++) {
            if (board[i][col] == num) {
                return false;
            }
        }
        int start_row = row - row % 3;
        int start_col = col - col % 3;
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                if (board[i + start_row][j + start_col] == num) {
                    return false;
                }
            }
        }
        return true;
    }

    bool solve_sudoku(vector<vector<int>>& board) {
        for (int i = 0; i < 9; i++) {
            for (int j = 0; j < 9; j++) {
                if (board[i][j] == 0) {
                    for (int num = 1; num <= 9; num++) {
                        if (is_valid(board, i, j, num)) {
                            board[i][j] = num;
                            if (solve_sudoku(board)) {
                                return true;
                            }
                            board[i][j] = 0;
                        }
                    }
                    return false;
                }
            }
        }
        return true;
    }

    void solve(vector<vector<int>>& board) {
        solve_sudoku(board);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<vector<int>> board(n, vector<int>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> board[i][j];
        }
    }
    Solution sol;
    sol.solve(board);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cout << board[i][j] << (j == n - 1 ? "\n" : " ");
        }
    }
    return 0;
}
